   305→  function performUpkeep(
   306→    bytes calldata performData
   307→  ) external whenNotPaused whenAssetOutConfigured onlyRole(Roles.AUCTION_WORKER_ROLE) {
   308→    (Common.AssetAmount[] memory eligibleAssets, address[] memory endedAuctions) =
   309→      abi.decode(performData, (Common.AssetAmount[], address[]));
   310→
   311→    // We should never pass a list of eligible assets with a non valid asset out price.
   312→    uint256 assetOutPrice;
   313→    address assetOut = s_assetOut;
   314→    if (eligibleAssets.length > 0) {
   315→      (assetOutPrice,,) = _getAssetPrice(assetOut, true);
   316→    }
   317→
   318→    bool hasFeeAggregator = address(s_feeAggregator) != address(this);
   319→
   320→    if (hasFeeAggregator && eligibleAssets.length > 0) {
   321→      s_feeAggregator.transferForSwap(address(this), eligibleAssets);
   322→    }
   323→
   324→    for (uint256 i; i < eligibleAssets.length; ++i) {
   325→      address asset = eligibleAssets[i].asset;
   326→
   327→      if (s_auctionStarts[asset] != 0) {
   328→        revert LiveAuction();
   329→      }
   330→
   331→      AssetParams storage assetParams = s_assetParams[asset];
   332→      uint8 assetDecimals = assetParams.decimals;
   333→
   334→      if (assetDecimals == 0) {
   335→        revert AssetParamsNotSet(asset);
   336→      }
   337→
   338→      uint256 assetPrice;
   339→      if (asset == assetOut) {
   340→        assetPrice = assetOutPrice;
   341→      } else {
   342→        (assetPrice,,) = _getAssetPrice(asset, true);
   343→      }
   344→      uint256 availableAssetUsdValue = (eligibleAssets[i].amount * assetPrice) / (10 ** assetDecimals);
   345→
   346→      if (availableAssetUsdValue < assetParams.minAuctionSizeUsd) {
   347→        revert AmountBelowMinAuctionSize(availableAssetUsdValue, assetParams.minAuctionSizeUsd);
   348→      }
   349→
   350→      if (asset == s_assetOut) {
   351→        IERC20(asset).safeTransfer(s_assetOutReceiver, IERC20(asset).balanceOf(address(this)));
   352→      } else {
   353→        s_auctionStarts[asset] = block.timestamp;
   354→        _onAuctionStart(asset);
   355→        emit AuctionStarted(asset);
   356→      }
   357→    }
   358→
   359→    for (uint256 i; i < endedAuctions.length; ++i) {
   360→      address asset = endedAuctions[i];
   361→
   362→      if (s_auctionStarts[asset] == 0) {
   363→        revert InvalidAuction(asset);
   364→      }
   365→
   366→      _onAuctionEnd(endedAuctions[i], hasFeeAggregator);
   367→      delete s_auctionStarts[asset];
   368→      emit AuctionEnded(asset);
   369→    }
   370→  }
   371→
   372→  /// @dev This function is virtual for potential integration e.g. approving tokens to external contracts not solving
   373→  /// through the bid() function.
   374→  /// @param asset The address of the asset being auctioned.
   375→  function _onAuctionStart(
   376→    address asset
   377→  ) internal virtual {}
   378→
   379→  /// @dev Ends an auction for a specific asset by transferring any remaining asset balance to the fee aggregator and
   380→  /// transferring all asset out balance to the asset out receiver.
   381→  /// @param asset The address of the asset being auctioned.
   382→  /// @param hasFeeAggregator Whether a fee aggregator is configured.
   383→  function _onAuctionEnd(
   384→    address asset,
   385→    bool hasFeeAggregator
